code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon } from 'decantr/components';

code.example:
function RentReminderUpcoming({ amount, dueDate, daysUntil }) {
  const { div, span, p } = tags;

  return div({ class: css('estate-card _p4 _flex _aic _gap4 _borderL[4px] _borderPrimary') },
    div({ class: css('_w10 _h10 _r2 _bgPrimary/10 _flex _aic _jcc') },
      icon('calendar', { class: css('_fgPrimary') })
    ),
    div({ class: css('_flex1') },
      span({ class: css('_font500 _block') }, 'Rent Payment Due Soon'),
      p({ class: css('_textsm _fgmuted') },
        `Due in ${daysUntil} day${daysUntil === 1 ? '' : 's'} (${new Date(dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })})`
      )
    ),
    span({ class: css('_heading4') }, `$${amount.toLocaleString()}`),
    link({ href: '/tenant-portal/payments' },
      Button({ variant: 'primary' }, 'Pay Now')
    )
  );
}

