code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon } from 'decantr/components';

code.example:
function RentReminderOverdue({ amount, lateFee, daysOverdue, gracePeriodRemaining }) {
  const { div, span, p } = tags;
  const total = amount + lateFee;

  return div({ class: css('estate-card _p4 _flex _aic _gap4 _borderL[4px] _borderDanger _bgDanger/5') },
    div({ class: css('_w10 _h10 _r2 _bgDanger/10 _flex _aic _jcc') },
      icon('alert-triangle', { class: css('_fgdanger') })
    ),
    div({ class: css('_flex1') },
      span({ class: css('_font500 _block _fgdanger') }, 'Rent Payment Overdue'),
      p({ class: css('_textsm _fgmuted') },
        daysOverdue === 1 ? '1 day overdue' : `${daysOverdue} days overdue`,
        lateFee > 0 ? ` • Late fee: $${lateFee}` : '',
        gracePeriodRemaining > 0 ? ` • Grace period: ${gracePeriodRemaining} days left` : ''
      )
    ),
    div({ class: css('_tr') },
      span({ class: css('_heading4 _block') }, `$${total.toLocaleString()}`),
      lateFee > 0 ? span({ class: css('_textxs _fgdanger') }, `Includes $${lateFee} late fee`) : null
    ),
    link({ href: '/tenant-portal/payments' },
      Button({ variant: 'primary' }, 'Pay Now')
    )
  );
}

